-- V7 · Remove demo users and keep only the admin account
--
-- Removes manager1 and staff1 seed accounts.
-- Renames the admin user to "Dissanayaka Admin".
-- Password for admin remains "admin123" (set in V6).
-- ─────────────────────────────────────────────────────────────────────────────

-- Remove demo/mock users
DELETE FROM users WHERE username IN ('manager1', 'staff1');

-- Update admin full name
UPDATE users
SET full_name = 'Dissanayaka Admin',
    email     = 'admin@dissanayake.lk'
WHERE username = 'admin';
